/// <summary>
/// Extension of the <c>PurchAgreementGenerateReleaseOrder</c> class for the ETGSPAIN model.
/// </summary>
[ExtensionOf(classStr(PurchAgreementGenerateReleaseOrder))]
final class PurchAgreementGenerateReleaseOrderETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Extension of the <c>initFromAgreementLineQuantityCommitment</c> method.
/// </summary>
/// <param name="_releaseOrderLine">TmpPurchLine</param>
/// <param name="_agreementLineQuantityCommitment">AgreementLineQuantityCommitment</param>
/// <remarks>
/// Initializes the contract value when dealing with quotas.
/// </remarks>
public void initFromAgreementLineQuantityCommitment(TmpPurchLine _releaseOrderLine, AgreementLineQuantityCommitment _agreementLineQuantityCommitment)
{
    next initFromAgreementLineQuantityCommitment(_releaseOrderLine, _agreementLineQuantityCommitment);

    AgreementHeader     agreementHeader = _agreementLineQuantityCommitment.agreementHeader();
    InventDim           inventDim;
    InventSerial        inventSerial;

    // Inicializamos el valor del contrato cuando se trata de Cupos
    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        if (agreementHeader.ETGSPAINPurchHasAgreementQuotas)
        {
            inventSerial = InventSerial::findOrCreate(_agreementLineQuantityCommitment.ETGSPAINLineCode, _agreementLineQuantityCommitment.ItemId);

            inventDim                      = _releaseOrderLine.inventDim();
            inventDim.inventSerialId       = inventSerial.InventSerialId;
            inventDim                      = InventDim::findOrCreate(inventDim);
            _releaseOrderLine.InventDimId  = inventDim.inventDimId;
        }
    }
}
